import React, { useState, useEffect, useMemo } from "react";
import axios from "axios";
import Cookies from "js-cookie";
import { useNavigate } from "react-router-dom";
import { Modal } from "bootstrap";
import { toast } from "react-toastify";
import Toast from "../components/Toast";
import dayjs from "dayjs";

const API_BASE_URL =
  process.env.REACT_APP_API_BASE_URL || "http://localhost:5000/api";

function SupportManagement() {
  const [supports, setSupports] = useState([]);
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const [filters, setFilters] = useState({
    search: "",
    status: "",
  });

  const [currentPage, setCurrentPage] = useState(1);
  const groupsPerPage = 5;

  const [formData, setFormData] = useState({
    id: null,
    description: "",
    status: "",
  });

//   const [detailsSupport, setDetailsSupport] = useState(null);

  /* ================= FETCH ================= */
  function fetchSupports() {
    setLoading(true);
    const token = Cookies.get("adminToken");

    axios
      .get(API_BASE_URL + "/supports", {
        headers: { Authorization: "Bearer " + token },
      })
      .then((res) => {
        if (res.data.success) {
          setSupports(res.data.data);
        } else {
          toast.error("Failed to fetch supports");
        }
      })
      .catch(() => toast.error("Error fetching supports"))
      .finally(() => setLoading(false));
  }

  useEffect(() => {
    const token = Cookies.get("adminToken");
    if (!token) navigate("/");
    else fetchSupports();
  }, [navigate]);

  /* ================= FILTER ================= */
  function handleFilterChange(e) {
    const { name, value } = e.target;
    setFilters((prev) => ({ ...prev, [name]: value }));
    setCurrentPage(1);
  }

  /* ================= GROUPING ================= */
  const groupedSupports = useMemo(() => {
    const mains = supports.filter((s) => s.reqType === "Main");

    return mains.map((main) => {
      const followups = supports
        .filter(
          (f) =>
            f.reqType === "Followup" &&
            f.reqId === main.id
        )
        .sort((a, b) => new Date(a.createdAt) - new Date(b.createdAt));

      return { main, followups };
    });
  }, [supports]);

  /* ================= FILTER ON GROUP ================= */
  const filteredGroups = groupedSupports.filter((group) => {
    const text =
      group.main.description +
      group.main.userFullName +
      group.main.employeeName;

    const searchMatch = filters.search
      ? text.toLowerCase().includes(filters.search.toLowerCase())
      : true;

    const statusMatch = filters.status
      ? group.main.status === filters.status
      : true;

    return searchMatch && statusMatch;
  });

  /* ================= PAGINATION ================= */
  const indexOfLast = currentPage * groupsPerPage;
  const indexOfFirst = indexOfLast - groupsPerPage;
  const currentGroups = filteredGroups.slice(
    indexOfFirst,
    indexOfLast
  );

  const totalPages = Math.ceil(
    filteredGroups.length / groupsPerPage
  );

  /* ================= EDIT ================= */
  function handleEdit(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be edited");
      return;
    }

    setFormData({
      id: support.id,
      description: support.description,
      status: support.status,
    });

    new Modal(document.getElementById("editModal")).show();
  }

  function handleSubmit(e) {
    e.preventDefault();
    const token = Cookies.get("adminToken");

    axios
      .put(API_BASE_URL + "/supports/" + formData.id, formData, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Followup updated");
        fetchSupports();
        Modal.getInstance(document.getElementById("editModal")).hide();
      })
      .catch(() => toast.error("Update failed"));
  }

  /* ================= DELETE ================= */
  function handleDelete(support) {
    if (support.reqType !== "Followup") {
      toast.error("Main request cannot be deleted");
      return;
    }

    if (!window.confirm("Delete this followup?")) return;

    const token = Cookies.get("adminToken");

    axios
      .delete(API_BASE_URL + "/supports/" + support.id, {
        headers: { Authorization: "Bearer " + token },
      })
      .then(() => {
        toast.success("Deleted");
        fetchSupports();
      })
      .catch(() => toast.error("Delete failed"));
  }

  /* ================= UI ================= */
  return (
    <div className="container mt-3">
      <Toast />
      <h4 className="fw-bold mb-3">Support Management</h4>

      {/* Filters */}
      <div className="row g-3 mb-3">
        <div className="col-md-6">
          <input
            type="text"
            name="search"
            className="form-control form-control-sm"
            placeholder="Search..."
            value={filters.search}
            onChange={handleFilterChange}
          />
        </div>

        <div className="col-md-6">
          <select
            name="status"
            className="form-select form-select-sm"
            value={filters.status}
            onChange={handleFilterChange}
          >
            <option value="">Status</option>
            <option value="Open">Open</option>
            <option value="In Progress">In Progress</option>
            <option value="Closed">Closed</option>
          </select>
        </div>
      </div>

      <div className="card">
        {loading ? (
          <div className="text-center p-3">Loading...</div>
        ) : (
          <div className="table-responsive">
            <table className="table table-bordered small">
              <thead className="table-dark">
                <tr>
                  <th>ID</th>
                  <th>Type</th>
                  <th>User</th>
                  <th>Employee</th>
                  <th>Status</th>
                  <th>Description</th>
                  <th>Date</th>
                  <th>Actions</th>
                </tr>
              </thead>
              <tbody>
                {currentGroups.map((group) => (
                  <React.Fragment key={group.main.id}>
                    {/* MAIN */}
                    <tr className="table-primary">
                      <td>{group.main.id}</td>
                      <td>
                        <span className="badge bg-primary">
                          Main
                        </span>
                      </td>
                      <td>{group.main.userFullName}</td>
                      <td>{group.main.employeeName}</td>
                      <td>{group.main.status}</td>
                      <td>{group.main.description}</td>
                      <td>
                        {dayjs(group.main.createdAt).format(
                          "DD MMM YYYY hh:mm A"
                        )}
                      </td>
                      <td>-</td>
                    </tr>

                    {/* FOLLOWUPS */}
                    {group.followups.map((f) => (
                      <tr key={f.id}>
                        <td>{f.id}</td>
                        <td>
                          <span className="badge bg-warning text-dark">
                            Followup
                          </span>
                        </td>
                        <td>-</td>
                        <td>{f.employeeName}</td>
                        <td>{f.status}</td>
                        <td className="ps-4">
                          ↳ {f.description}
                        </td>
                        <td>
                          {dayjs(f.createdAt).format(
                            "DD MMM YYYY hh:mm A"
                          )}
                        </td>
                        <td>
                          <i
                            className="fa-solid fa-pen text-primary me-2"
                            style={{ cursor: "pointer" }}
                            onClick={() => handleEdit(f)}
                          ></i>
                          <i
                            className="fa-solid fa-trash text-danger"
                            style={{ cursor: "pointer" }}
                            onClick={() => handleDelete(f)}
                          ></i>
                        </td>
                      </tr>
                    ))}
                  </React.Fragment>
                ))}
              </tbody>
            </table>
          </div>
        )}
      </div>

      {/* Pagination */}
      <div className="d-flex justify-content-between mt-3">
        <div>
          Page {currentPage} of {totalPages || 1}
        </div>
        <div>
          <button
            className="btn btn-sm btn-light me-2"
            disabled={currentPage === 1}
            onClick={() => setCurrentPage((p) => p - 1)}
          >
            Prev
          </button>
          <button
            className="btn btn-sm btn-light"
            disabled={currentPage === totalPages}
            onClick={() => setCurrentPage((p) => p + 1)}
          >
            Next
          </button>
        </div>
      </div>

      {/* Edit Modal */}
      <div className="modal fade" id="editModal">
        <div className="modal-dialog">
          <div className="modal-content">
            <form onSubmit={handleSubmit}>
              <div className="modal-header">
                <h5>Edit Followup</h5>
                <button
                  className="btn-close"
                  data-bs-dismiss="modal"
                ></button>
              </div>
              <div className="modal-body">
                <select
                  className="form-select mb-3"
                  value={formData.status}
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      status: e.target.value,
                    })
                  }
                >
                  <option value="In Progress">
                    In Progress
                  </option>
                  <option value="Closed">Closed</option>
                </select>

                <textarea
                  className="form-control"
                  value={formData.description}
                  onChange={(e) =>
                    setFormData({
                      ...formData,
                      description: e.target.value,
                    })
                  }
                  required
                />
              </div>
              <div className="modal-footer">
                <button className="btn btn-primary">
                  Update
                </button>
              </div>
            </form>
          </div>
        </div>
      </div>
    </div>
  );
}

export default SupportManagement;
